{
  "terms": [
    {
      "term": "Transposition",
      "simpleDefinition": "The process of rearranging a mathematical formula to solve for a different unknown value.",
      "anchor": "Rearranging V = I × R to find Resistance (R = V / I).",
      "misconception": "Believing you can move a number to the other side of the equals sign without reversing its mathematical operation."
    },
    {
      "term": "Indices",
      "simpleDefinition": "Small numbers (powers) that show how many times a base number is multiplied by itself, often used in powers of 10.",
      "anchor": "Using 10³ to represent 'kilo' (1,000) or 10⁻³ for 'milli' (0.001).",
      "misconception": "Confusing the index with a simple multiplier, such as thinking 10² is 20 instead of 100."
    },
    {
      "term": "Pythagoras’ Theorem",
      "simpleDefinition": "A formula used to find the length of a missing side in a right-angled triangle (a² + b² = c²).",
      "anchor": "Calculating the total Impedance (hypotenuse) when you know Resistance and Reactance.",
      "misconception": "Forgetting to find the square root of the final sum to get the actual side length."
    },
    {
      "term": "Trigonometry (SOH CAH TOA)",
      "simpleDefinition": "The study of the relationship between the angles and sides of a triangle.",
      "anchor": "Using the Cosine (CAH) to calculate the Power Factor from a power triangle.",
      "misconception": "Incorrectly identifying the 'Opposite' and 'Adjacent' sides because the reference angle was swapped."
    },
    {
      "term": "Derating Factor",
      "simpleDefinition": "A percentage or decimal used to reduce the maximum current a cable can safely carry based on its environment.",
      "anchor": "Applying a 0.8 multiplier to a cable's rating to account for high ambient temperatures.",
      "misconception": "Thinking a 10% reduction means multiplying by 0.1 rather than 0.9."
    },
    {
      "term": "Arithmetic Mean",
      "simpleDefinition": "The average value calculated by adding a set of numbers together and dividing by how many numbers there are.",
      "anchor": "Taking three separate insulation resistance readings and finding the average result.",
      "misconception": "Confusing the 'mean' (average) with the 'median' (the middle number in a list)."
    },
    {
      "term": "Variable",
      "simpleDefinition": "A letter used in a formula to represent a physical quantity that can change.",
      "anchor": "Using 'I' to represent Current or 'P' to represent Power.",
      "misconception": "Assuming a letter like 'V' always represents a fixed number rather than a value that must be measured or calculated."
    }
  ],
  "anchorPhrases": [
    "Change the side, change the sign.",
    "SOH CAH TOA.",
    "Square it, add it, root it.",
    "Powers of ten for units.",
    "Isolate the unknown."
  ],
  "misconceptionTargets": [
    "Moving a number across the equals sign without changing the operation.",
    "Treating indices as simple multiplication.",
    "Mixing up the adjacent and opposite sides in a triangle.",
    "Applying percentage reductions as the multiplier itself (e.g., using 0.2 for a 20% drop instead of 0.8)."
  ]
}

{
  "teachChecks": [
    {
      "title": "Fractions, Percentages, and Indices",
      "basicQuestions": [
        {
          "questionText": "What is the decimal equivalent of a 10% derating factor used in cable calculations?",
          "answerGuidance": [
            "0.1",
            "zero point one"
          ],
          "hint": "Divide the percentage by 100.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "Which mathematical notation uses a base number and a power to represent very large or small electrical units?",
          "answerGuidance": [
            "Indices",
            "Powers of ten",
            "Scientific notation"
          ],
          "hint": "Think of the small number written above a base like 10.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What power of ten (index) is used to represent the prefix 'kilo' in electrical units?",
          "answerGuidance": [
            "10³",
            "10^3",
            "10 to the power of 3"
          ],
          "hint": "Kilo represents one thousand.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        }
      ],
      "deeperQuestionText": "Why must an electrician convert a percentage rating factor into a decimal before applying it to a cable's current-carrying capacity?",
      "deeperAnswerGuidance": [
        "Percentages are ratios and cannot be directly multiplied in standard equations",
        "Decimals allow for direct multiplication with the base unit",
        "Ensures the correct reduction or increase is applied to the numerical value",
        "Calculators and formulas require numerical values rather than percentage symbols"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3"
      ],
      "hint": "Think about how a calculator processes a percentage versus a standard number."
    },
    {
      "title": "Algebra and Transposition",
      "basicQuestions": [
        {
          "questionText": "What is the term for the process of rearranging a formula to solve for a different unknown variable?",
          "answerGuidance": [
            "Transposition",
            "Transposing"
          ],
          "hint": "It involves moving terms across the equals sign.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "In the formula V = I × R, what mathematical operation must be used to move the 'I' to the other side of the equals sign?",
          "answerGuidance": [
            "Division",
            "Divide"
          ],
          "hint": "You must perform the opposite of the current operation.",
          "sourceTeachingPointIds": [
            "TP1",
            "TP2"
          ]
        },
        {
          "questionText": "What is the core rule regarding the mathematical operation when a value is moved across the equals sign?",
          "answerGuidance": [
            "Change the operation",
            "Reverse the operation",
            "Do the opposite",
            "Change the sign"
          ],
          "hint": "If it was multiplying on one side, what does it do on the other?",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "If you are given the Power (P) and the Current (I), why is transposition necessary before you can calculate the Resistance (R)?",
      "deeperAnswerGuidance": [
        "The unknown variable must be isolated on one side of the equals sign",
        "Standard formulas are often arranged for a different subject like Power",
        "It ensures the correct order of operations is followed for the specific unknown",
        "Prevents calculation errors by establishing the correct relationship between P and I first"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2"
      ],
      "hint": "Consider what happens if you try to calculate a value that is still 'stuck' next to other numbers in a formula."
    },
    {
      "title": "Triangles and Trigonometry",
      "basicQuestions": [
        {
          "questionText": "Which mathematical theorem is used to calculate the length of the hypotenuse in a right-angled triangle?",
          "answerGuidance": [
            "Pythagoras’ Theorem",
            "Pythagoras"
          ],
          "hint": "It uses the formula a² + b² = c².",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "In the acronym SOH CAH TOA, what trigonometric ratio does the 'C' represent?",
          "answerGuidance": [
            "Cosine",
            "Cos"
          ],
          "hint": "It relates the adjacent side to the hypotenuse.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "In an electrical impedance triangle, which side of the triangle represents the total impedance?",
          "answerGuidance": [
            "Hypotenuse",
            "Longest side"
          ],
          "hint": "This is the side opposite the right angle.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "How does the selection of the reference angle determine which sides of a right-angled triangle are labeled as 'Opposite' and 'Adjacent'?",
      "deeperAnswerGuidance": [
        "The labels are relative to the position of the angle being measured",
        "The opposite side is always directly across from the reference angle",
        "The adjacent side is the one next to the reference angle that is not the hypotenuse",
        "Swapping the reference angle swaps the labels of the two shorter sides"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2"
      ],
      "hint": "Think about how the names of the sides change if you look at the triangle from the other sharp corner."
    },
    {
      "title": "Statistics in Electrical Work",
      "basicQuestions": [
        {
          "questionText": "What is the technical term for the average value found by adding a set of test results and dividing by the total number of results?",
          "answerGuidance": [
            "Arithmetic Mean",
            "Mean"
          ],
          "hint": "It is the most common type of average used in electrical reporting.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What statistical value is an electrician calculating when they subtract the lowest test reading from the highest?",
          "answerGuidance": [
            "Range",
            "Data range"
          ],
          "hint": "This shows the spread of the results.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "Which statistical principle is used to determine a representative value from multiple insulation resistance readings?",
          "answerGuidance": [
            "Arithmetic Mean",
            "Average",
            "Mean"
          ],
          "hint": "You add them up and divide by the count.",
          "sourceTeachingPointIds": [
            "TP1",
            "TP2"
          ]
        }
      ],
      "deeperQuestionText": "Why is calculating the arithmetic mean of several test readings more reliable than relying on a single measurement for a load profile?",
      "deeperAnswerGuidance": [
        "It accounts for fluctuations in electrical demand over time",
        "It reduces the impact of a single unusual or outlier reading",
        "Provides a more accurate representation of the typical circuit behavior",
        "Ensures that temporary spikes or drops do not skew the overall data set"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3"
      ],
      "hint": "Consider what happens to your data if one single reading is taken during a momentary power surge."
    }
  ]
}

